UploadBlob and DownloadBlob use gRPC streaming to handle large blobs efficiently without buffering the entire ciphertext in memory. message UploadBlobChunk { string hash = 1; // SHA-256 of the plaintext (blob identifier) bytes chunk = 2; // ciphertext chunk
} message DownloadBlobChunk { bytes chunk = 1; // ciphertext chunk
}
